#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        if (scanf("%d", &N) != 1) return 0;
        char s[1005];
        scanf("%s", s);
        for (int i = 0; i < N; ++i) {
            if (s[i] == 'D')
                printf("Woof\n");
            else if (s[i] == 'C')
                printf("Meow\n");
        }
    }
    return 0;
}

